/* ═══════════════════════════════════════════════════════════
   FALL TOWN PATCH v2.0.1 — Seasonal HUD button + town styles
   ═══════════════════════════════════════════════════════════ */

/* Default (Spring) town button — soft green */
#hud-town-btn {
  background: linear-gradient(135deg, #16a34a, #15803d) !important;
  border-color: #15803d !important;
  box-shadow: 0 2px 8px rgba(22, 163, 74, .35) !important;
}
body.dark #hud-town-btn {
  background: linear-gradient(135deg, #15803d, #166534) !important;
  border-color: #166534 !important;
}
body.retro #hud-town-btn {
  background: #0a2e0e !important;
  border: 2px solid #1b6b24 !important;
  border-radius: 3px !important;
  font-family: 'Press Start 2P', monospace !important;
  font-size: 6.5px !important;
  box-shadow: none !important;
  color: #a5d6a7 !important;
  padding: 4px 7px !important;
}

/* Summer town button — golden amber */
body.season-summer #hud-town-btn {
  background: linear-gradient(135deg, #d97706, #b45309) !important;
  border-color: #b45309 !important;
  box-shadow: 0 2px 8px rgba(217, 119, 6, .35) !important;
}
body.dark.season-summer #hud-town-btn {
  background: linear-gradient(135deg, #b45309, #92400e) !important;
  border-color: #92400e !important;
}

/* Fall town button — original warm orange (from fall_town.js) */
body.season-fall #hud-town-btn {
  background: linear-gradient(135deg, #c2410c, #9a3412) !important;
  border-color: #9a3412 !important;
  box-shadow: 0 2px 8px rgba(194, 65, 12, .35) !important;
}
body.dark.season-fall #hud-town-btn {
  background: linear-gradient(135deg, #9a3412, #7c2d12) !important;
  border-color: #7c2d12 !important;
}

/* Winter town button — cool blue */
body.season-winter #hud-town-btn {
  background: linear-gradient(135deg, #0369a1, #075985) !important;
  border-color: #075985 !important;
  box-shadow: 0 2px 8px rgba(3, 105, 161, .35) !important;
}
body.dark.season-winter #hud-town-btn {
  background: linear-gradient(135deg, #075985, #0c4a6e) !important;
  border-color: #0c4a6e !important;
}

/* Ensure fall-glow and fall-leaves are present in the DOM at all times
   (fall_town.js may create them during boot when game-screen is hidden,
   which can cause positioning issues on some browsers) */
#fall-glow   { will-change: opacity; }
#fall-leaves { will-change: contents; }

