(function () {
  'use strict';

  /* ═══════════════════════════════════════════════════════════
     FALL TOWN PATCH v2.0.2
     fall_town.js v2.0.0 had a subtle boot-timing bug:
       whenReady() checked "typeof G !== 'undefined'" but
       script.js declares "let G = {}", so G is always an
       object — never undefined.  Boot therefore fired
       immediately at page load (before any user logged in),
       at which point G.si was undefined and
       window.openTownScreen had not yet been assigned.

     This was fixed in fall_town.js v2.0.1 by changing the
     whenReady guard to also require typeof G.si === 'number'.
     boot() now correctly fires only after login.

     What this patch still provides:
       1. Seasonal CSS: HUD Town button colour per season.
       2. Season body-class helper (body.season-*) so CSS can
          key the button colour without JS changes.
       3. doSleep hook: keeps body.season-* class in sync each
          morning so the HUD button always shows the right colour
          after a season change during sleep.
  ═══════════════════════════════════════════════════════════ */

  /* ── Seasonal body-class helper ──────────────────────────── */
  var SEASON_CLASSES = ['season-spring', 'season-summer', 'season-fall', 'season-winter'];
  var SEASON_BODY_MAP = {
    Spring: 'season-spring', Summer: 'season-summer',
    Fall:   'season-fall',   Winter: 'season-winter'
  };

  function applySeasonBodyClass() {
    var s = (typeof season === 'function') ? season() : null;
    SEASON_CLASSES.forEach(function (cls) { document.body.classList.remove(cls); });
    if (s && SEASON_BODY_MAP[s]) document.body.classList.add(SEASON_BODY_MAP[s]);
  }

  /* ── Hook launchGame to apply season class on every login ─── */
  /* launchGame is a global function declaration in script.js, so
     window.launchGame is the same binding. Wrapping it here means
     applySeasonBodyClass() fires whenever the game screen is shown,
     including on re-login after logout.                          */
  var _origLaunchGame = window.launchGame;
  if (typeof _origLaunchGame === 'function') {
    window.launchGame = function () {
      _origLaunchGame.apply(this, arguments);
      /* 600 ms: fall_town.js boot() has already fired (~200 ms),
         G.town is initialised, season() is valid.               */
      setTimeout(applySeasonBodyClass, 600);
    };
    console.log('[FallTownPatch v2.0.2] launchGame hooked for season body class.');
  }

  /* ── Hook doSleep to keep body.season-* in sync ─────────── */
  /* After sleep the day advances, potentially changing season.
     fall_town.js already hooks doSleep for atmosphere; we add
     another wrapper here solely for the CSS body class.        */
  function hookSleepSeasonClass() {
    if (typeof window.doSleep !== 'function') {
      setTimeout(hookSleepSeasonClass, 200);
      return;
    }
    var _origSleep = window.doSleep;
    window.doSleep = function () {
      var ret = _origSleep.apply(this, arguments);
      setTimeout(applySeasonBodyClass, 700);
      return ret;
    };
    console.log('[FallTownPatch v2.0.2] doSleep hooked for seasonal body class sync.');
  }
  /* Poll briefly so our wrapper runs after fall_town.js's hookSleep()
     has already wrapped doSleep (fall_town.js boot fires at ~200 ms
     after login; we set 400 ms to be safely after that).           */
  setTimeout(hookSleepSeasonClass, 400);

  console.log('[FallTownPatch v2.0.2] Loaded.');
})();
